import pytest
from domain_rules import get_forbidden_patterns, ALL_RULES

def test_get_forbidden_patterns_count_matches_all_rules():
    patterns = get_forbidden_patterns()
    expected = sum(len(v) for v in ALL_RULES.values())
    assert len(patterns) == expected

def test_get_forbidden_patterns_dict_keys():
    required = {"id", "pattern", "severity", "description", "fix_hint"}
    for p in get_forbidden_patterns():
        assert required.issubset(p.keys()), f"Missing keys in {p}"

def test_get_forbidden_patterns_severity_values():
    valid = {"CRITICAL", "HIGH", "MEDIUM", "LOW"}
    for p in get_forbidden_patterns():
        assert p["severity"] in valid, f"Unexpected severity: {p['severity']}"

