def single_category_rules_dict(monkeypatch):
    """Patch ALL_RULES with a single, minimal category for isolation."""
    import domain_rules
    minimal = {"python": ALL_RULES["python"]}
    monkeypatch.setattr(domain_rules, "ALL_RULES", minimal)
    return minimal

from domain_rules import ALL_RULES, SECURITY_RULES, AIRFLOW_RULES, PYSPARK_RULES, PYTHON_RULES

def test_all_rules_registers_every_rule_list():
    expected = {
        "security": SECURITY_RULES,
        "airflow": AIRFLOW_RULES,
        "pyspark": PYSPARK_RULES,
        "python": PYTHON_RULES,
    }
    assert ALL_RULES == expected
